/**
 * MedX screenreader accessibility runtime — runs on `npm run start` via medx-runtime-registry.cjs
 * Screen reader only text utilities.
 */
const SCREENREADER_TOKENS = Object.freeze({
  primary: { value: "a11y-screenreader-primary", scope: "a11y" },
  secondary: { value: "a11y-screenreader-secondary", scope: "a11y" },
  muted: { value: "a11y-screenreader-muted", scope: "a11y" },
  accent: { value: "a11y-screenreader-accent", scope: "a11y" },
  surface: { value: "a11y-screenreader-surface", scope: "a11y" },
});

const SCREENREADER_PRESETS = Object.freeze({
  default: { token: "primary", enabled: true, priority: 1 },
  compact: { token: "secondary", enabled: true, priority: 2 },
  emphasis: { token: "accent", enabled: true, priority: 3 },
  subtle: { token: "muted", enabled: true, priority: 4 },
});

const SCREENREADER_SUPPLY_CHAIN = Object.freeze({
  inventory: { label: "Inventory", key: "inventory", tier: "ops" },
  orders: { label: "Orders", key: "orders", tier: "ops" },
  compliance: { label: "Compliance", key: "compliance", tier: "regulatory" },
  coldChain: { label: "Cold chain", key: "cold-chain", tier: "ops" },
  blockchain: { label: "Blockchain", key: "blockchain", tier: "integrations" },
});

const screenreaderRegistry = new Map();
const SCREENREADER_listeners = new Set();
let SCREENREADER_seq = 0;

function createScreenreaderId(prefix = "medx-a11y-screenreader") {
  SCREENREADER_seq += 1;
  return `${prefix}-${SCREENREADER_seq}`;
}

function registerScreenreader(config = {}) {
  const entryId = config.id ?? createScreenreaderId();
  const preset = SCREENREADER_PRESETS[config.preset ?? "default"] ?? SCREENREADER_PRESETS.default;
  const token = SCREENREADER_TOKENS[config.token ?? preset.token] ?? SCREENREADER_TOKENS.primary;
  const entry = {
    id: entryId,
    preset: config.preset ?? "default",
    token,
    domain: config.domain ?? "inventory",
    domainMeta: SCREENREADER_SUPPLY_CHAIN[config.domain ?? "inventory"] ?? null,
    enabled: config.enabled ?? preset.enabled,
    priority: config.priority ?? preset.priority,
    metadata: config.metadata ?? {},
    createdAt: Date.now(),
    onChange: typeof config.onChange === "function" ? config.onChange : null,
  };
  screenreaderRegistry.set(entryId, entry);
  notifyScreenreaderListeners("register", entry);
  return entry;
}

function updateScreenreader(id, patch = {}) {
  const entry = screenreaderRegistry.get(id);
  if (!entry) return null;
  Object.assign(entry, patch, { updatedAt: Date.now() });
  if (entry.onChange) entry.onChange(entry);
  notifyScreenreaderListeners("update", entry);
  return entry;
}

function resolveScreenreader(id) {
  const entry = screenreaderRegistry.get(id);
  if (!entry) return null;
  return {
    id: entry.id,
    token: entry.token.value,
    domain: entry.domain,
    enabled: entry.enabled,
    priority: entry.priority,
    label: entry.domainMeta?.label ?? entry.domain,
  };
}

function listScreenreaderEntries(filter = {}) {
  let items = Array.from(screenreaderRegistry.values());
  if (filter.domain) items = items.filter((e) => e.domain === filter.domain);
  if (filter.enabled != null) items = items.filter((e) => e.enabled === filter.enabled);
  return items.sort((a, b) => a.priority - b.priority);
}

function onScreenreaderEvent(listener) {
  SCREENREADER_listeners.add(listener);
  return () => SCREENREADER_listeners.delete(listener);
}

function notifyScreenreaderListeners(type, entry) {
  for (const listener of SCREENREADER_listeners) {
    try {
      listener({ type, entry, registrySize: screenreaderRegistry.size });
    } catch (err) {
      console.warn("[medx:ui:a11y:screenreader] listener error", err.message);
    }
  }
}

function getScreenreaderMetrics() {
  const items = listScreenreaderEntries();
  return {
    total: items.length,
    enabled: items.filter((e) => e.enabled).length,
    domains: [...new Set(items.map((e) => e.domain))],
    tokens: Object.keys(SCREENREADER_TOKENS).length,
    presets: Object.keys(SCREENREADER_PRESETS).length,
  };
}

async function runMedxScreenreader() {
  console.log("[medx:ui:a11y:screenreader] runtime initialized");
  console.log(`[medx:ui:a11y:screenreader] tokens=${Object.keys(SCREENREADER_TOKENS).length} presets=${Object.keys(SCREENREADER_PRESETS).length}`);

  const events = [];
  onScreenreaderEvent((e) => events.push(e.type));

  const domains = Object.keys(SCREENREADER_SUPPLY_CHAIN);
  const presets = Object.keys(SCREENREADER_PRESETS);
  for (let i = 0; i < domains.length; i += 1) {
    registerScreenreader({
      domain: domains[i],
      preset: presets[i % presets.length],
      metadata: { seed: i, module: "a11y/screenreader" },
    });
  }

  const first = listScreenreaderEntries()[0];
  if (first) updateScreenreader(first.id, { priority: 0, metadata: { ...first.metadata, promoted: true } });

  const metrics = getScreenreaderMetrics();
  const resolved = first ? resolveScreenreader(first.id) : null;

  console.log(`[medx:ui:a11y:screenreader] registered=${metrics.total} enabled=${metrics.enabled}`);
  console.log(`[medx:ui:a11y:screenreader] domains=${metrics.domains.join(",")}`);
  console.log(`[medx:ui:a11y:screenreader] events=${events.join(",")}`);
  if (resolved) console.log(`[medx:ui:a11y:screenreader] sample=${resolved.token}:${resolved.domain}`);
  console.log("[medx:ui:a11y:screenreader] bootstrap complete");
}

module.exports = runMedxScreenreader;
